  v_processed   		CHAR(1);
  v_check_from  		VARCHAR2(200);
  v_check_up 			VARCHAR2(200);
  v_ssfi_banktransfer_id 	VARCHAR2(34);
  vAux NUMBER;
BEGIN

    IF AD_isTriggerEnabled()='N' THEN RETURN;
    END IF;

 --Check if trying to move object from module not in dev
  IF (INSERTING OR UPDATING ) THEN
	If(round(:NEW.total_checks,2) <= round(0,2))Then
		RAISE_APPLICATION_ERROR(-20000, 'El campo Total Cheques es menos a debe ser mayor a 0.');
	End IF;
  END IF;

END SSPCH_PDC_VALIDATIONS_TRG
